import{_ as t,o,c as e,a2 as a}from"./chunks/framework.DX8nTkPK.js";const m=JSON.parse('{"title":"CoreMod","description":"","frontmatter":{},"headers":[],"relativePath":"coremod/index.md","filePath":"coremod/index.md","lastUpdated":1778766727000}'),i={name:"coremod/index.md"};function d(n,r,l,s,c,h){return o(),e("div",null,[...r[0]||(r[0]=[a('<h1 id="coremod" tabindex="-1">CoreMod <a class="header-anchor" href="#coremod" aria-label="Permalink to &quot;CoreMod&quot;">​</a></h1><p>CoreMod 是一类 API 的统称，其典型用途是进行 <strong>ClassTransforming</strong>（类字节码变换），加载时机早于游戏本身。广义上，任何使用这些 API 的 Mod 都可以视为 CoreMod——即使它只是为了获得更早的加载时机而非真正修改类。</p><p>它们不同于普通 Mod 通过事件或 API 做上层扩展，而是直接操作 Minecraft 的类文件本身——修改方法体、替换字段访问、注入新逻辑。正因为如此，CoreMod 的实现方式随 Minecraft 版本和模组平台的不同而变化极大。</p><h2 id="版本与平台总览" tabindex="-1">版本与平台总览 <a class="header-anchor" href="#版本与平台总览" aria-label="Permalink to &quot;版本与平台总览&quot;">​</a></h2><p>CoreMod 的底层机制由版本决定，同一个版本区间内不同平台（Forge / Fabric / NeoForge）又有各自的实现体系。下面按版本梳理：</p><table tabindex="0"><thead><tr><th>版本区间</th><th>主流平台</th><th>CoreMod 实现方式</th></tr></thead><tbody><tr><td><strong>1.7.10 ~ 1.12.2</strong></td><td>Forge</td><td>IFMLLoadingPlugin / ICoreMod, LaunchWrapper 体系</td></tr><tr><td><strong>1.16.5</strong></td><td>Forge, Fabric</td><td>Forge: FML 2.0 体系; Fabric: Mixin + Access Wideners</td></tr><tr><td><strong>1.18 ~ 1.20.1</strong></td><td>Forge, Fabric</td><td>基本同 1.16.5，Forge 逐步转向 Mixin 为主</td></tr><tr><td><strong>1.20.6 ~ 1.21.8</strong></td><td>NeoForge, Fabric</td><td>NeoForge 继承 Forge 体系; Fabric 成熟 Mixin 生态</td></tr><tr><td><strong>1.21.9+</strong></td><td>NeoForge, Fabric</td><td>新版 NeoForge 加载器变化，需关注兼容性</td></tr></tbody></table><h2 id="内容结构" tabindex="-1">内容结构 <a class="header-anchor" href="#内容结构" aria-label="Permalink to &quot;内容结构&quot;">​</a></h2><h3 id="mixin-通用技术" tabindex="-1">Mixin（通用技术） <a class="header-anchor" href="#mixin-通用技术" aria-label="Permalink to &quot;Mixin（通用技术）&quot;">​</a></h3><p>Mixin 是当今 Minecraft Mod 开发中最核心的类注入框架，<strong>跨版本、跨平台通用</strong>。无论你写 Forge、NeoForge 还是 Fabric，Mixin 都是必备技能。</p><ul><li><a href="./mixin-basics.html">Mixin 入门</a> — 注解体系、Injection Point、配置与冲突解决</li><li><a href="./asm-bytecode.html">ASM 字节码操作</a> — ClassVisitor / MethodVisitor 原理与实战</li><li><a href="./debugging.html">调试与排错</a> — Stacktrace 分析、Mixin 冲突定位、IDE 调试技巧</li></ul><h3 id="各版本-coremod-体系" tabindex="-1">各版本 CoreMod 体系 <a class="header-anchor" href="#各版本-coremod-体系" aria-label="Permalink to &quot;各版本 CoreMod 体系&quot;">​</a></h3><ul><li><a href="./legacy-coremod.html">1.7.10 ~ 1.12.2</a> — LaunchWrapper、IFMLLoadingPlugin、Access Transformer 等早期体系</li><li><a href="./1.16.5.html">1.16.5</a> — FML 2.0 + Fabric 双平台 CoreMod 方案</li><li><a href="./1.18-1.20.1.html">1.18 ~ 1.20.1</a> — 过渡期，Mixin 逐渐成为主流</li><li><a href="./1.20.6-1.21.8.html">1.20.6 ~ 1.21.8</a> — NeoForge 崛起，Forge/Fabric 三足鼎立</li><li><a href="./1.21.9.html">1.21.9+</a> — 新版 NeoForge 加载器变更</li></ul><hr><div class="tip custom-block"><p class="custom-block-title">阅读建议</p><p>如果你是 CoreMod 新手，建议直接从 <strong>Mixin 入门</strong> 开始——它是当前所有平台和版本的通用基础设施。之后再根据需要查阅对应版本的 CoreMod 机制。</p></div>',14)])])}const M=t(i,[["render",d]]);export{m as __pageData,M as default};
